            aOrbiterH = RotL64((aOrbiterH * 0xD1BDB05C692A0EB5ULL), 3U);
            //
            aOrbiterB = (aOrbiterB + aOrbiterK) + 0xA0F3C3C784F2C2E7ULL;
            aOrbiterE = (aOrbiterE ^ aOrbiterB) ^ 0xA2E080DEC7654F48ULL;
