            //
            aOrbiterH = ((aOrbiterH + aOrbiterI) + 0xCBDB620D0EA404D8ULL) + aPhaseAOrbiterUpdateSaltB[(((31U - aIndex) + 18U)) & 31];
            aOrbiterB = (aOrbiterB ^ aOrbiterH) ^ 0x8BE9E96D4F6CBD36ULL;
            aOrbiterB = RotL64((aOrbiterB * 0x584B010124C24D1BULL), 19U);
