            aOrbiterJ = (aOrbiterJ + aOrbiterD) + 0x6779EC040DE048BBULL;
            aOrbiterB = (aOrbiterB ^ aOrbiterJ) ^ 0xC67B5C5849C1183CULL;
            aOrbiterB = RotL64((aOrbiterB * 0x6D5C61C1C2AEE525ULL), 11U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterB) + 0x8DB1DE0577225325ULL;
