            aWandererF = aWandererF + (((RotL64(aScatter, 35U) + aOrbiterI) + RotL64(aOrbiterK, 35U)) + aPhaseGWandererUpdateSaltF[(((31U - aIndex) + 10U)) & 31]);
            //
            aCarry = aCarry + (RotL64(aWandererA, 27U) ^ aWandererH);
